7	
8	type entry struct {
9		value     interface{}
10		expiresAt time.Time
11	}
12	
13	type HotCache struct {
14		mu    sync.RWMutex
15		items map[string]entry
16	}
17	
18	func New() *HotCache {
19		c := &HotCache{items: make(map[string]entry)}
20		go c.cleanup()
21		return c
22	}
23	
24	func (c *HotCache) Get(key string) (interface{}, bool) {
25		c.mu.RLock()
26		defer c.mu.RUnlock()
27		e, ok := c.items[key]
28		if !ok || time.Now().After(e.expiresAt) {
29			return nil, false
30		}
31		return e.value, true
32	}
33	
34	func (c *HotCache) Set(key string, value interface{}, ttl time.Duration) {
35		c.mu.Lock()
36		defer c.mu.Unlock()
37		c.items[key] = entry{value: value, expiresAt: time.Now().Add(ttl)}
38	}
39	
40	func (c *HotCache) Delete(key string) {
41		c.mu.Lock()
42		defer c.mu.Unlock()
43		delete(c.items, key)
44	}
45	
46	func (c *HotCache) DeletePrefix(prefix string) {
47		c.mu.Lock()
48		defer c.mu.Unlock()
49		for k := range c.items {
50			if len(k) >= len(prefix) && k[:len(prefix)] == prefix {
51				delete(c.items, k)
52			}
53		}
54	}
55	
56	func (c *HotCache) cleanup() {
57		ticker := time.NewTicker(5 * time.Minute)
58		defer ticker.Stop()
59		for range ticker.C {
60			c.mu.Lock()
61			now := time.Now()
62			for k, e := range c.items {
63				if now.After(e.expiresAt) {
64					delete(c.items, k)
65				}
66			}
67			c.mu.Unlock()
68		}
69	}
