143	// DownloadAttachment serves an attachment file by message ID. The internal
144	// filesystem path is never exposed to the client — only the opaque message
145	// UUID is needed to fetch the file.
146	func (h *MessageHandler) DownloadAttachment(c echo.Context) error {
147		msgID, err := uuid.Parse(c.Param("messageId"))
148		if err != nil {
149			return errorResponse(c, http.StatusBadRequest, dto.CodeValidation, "invalid message ID")
150		}
151	
152		userID, err := uuid.Parse(middleware.GetUserID(c))
153		if err != nil {
154			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "invalid user")
155		}
156	
157		msg, err := h.messageService.GetByID(c.Request().Context(), msgID, userID)
158		if err != nil {
159			return mapError(c, err)
160		}
161	
162		if msg.AttachmentPath == "" {
