169	// isTextAttachment returns true for file types whose content should be scanned as text.
170	func isTextAttachment(mime string, ext string) bool {
171		if strings.HasPrefix(mime, "text/") {
172			return true
173		}
174		ext = strings.ToLower(ext)
175		return ext == ".csv" || ext == ".txt"
176	}
177	
178	// safeBinaryMIMEs lists binary MIME types that are allowed as attachments.
179	// These formats cannot be meaningfully scanned for PII as plain text, but
180	// are common enough in a collectibles exchange that blocking them would
181	// break legitimate workflows (proof-of-authenticity photos, certificates, etc.).
182	var safeBinaryMIMEs = map[string]bool{
183		"image/jpeg":      true,
184		"image/png":       true,
185		"image/gif":       true,
186		"image/webp":      true,
187		"image/svg+xml":   true,
188		"application/pdf": true,
189	}
190	
191	// safeBinaryExts provides a fallback when the MIME type from the client
192	// is generic (e.g. application/octet-stream).
193	var safeBinaryExts = map[string]bool{
194		".jpg": true, ".jpeg": true, ".png": true, ".gif": true,
195		".webp": true, ".svg": true, ".pdf": true,
196	}
197	
198	// isSafeBinaryAttachment returns true for binary file types that are
199	// explicitly allowed. Anything not on this list and not scannable as text
200	// is rejected, preventing unscannable formats (DOCX, XLSX, etc.) from
201	// bypassing PII checks.
202	func isSafeBinaryAttachment(mime string, ext string) bool {
203		if safeBinaryMIMEs[mime] {
204			return true
205		}
206		return safeBinaryExts[strings.ToLower(ext)]
207	}
