23			`SELECT id, order_id, sender_id, body, attachment_path, attachment_size, attachment_mime, created_at
24			 FROM messages WHERE id = $1`, id).Scan(
25			&m.ID, &m.OrderID, &m.SenderID, &m.Body, &m.AttachmentPath,
