48			`SELECT COUNT(*) FROM messages WHERE order_id = $1`, orderID).Scan(&total)
49		if err != nil {
50			return nil, 0, err
51		}
52	
53		offset := (page - 1) * pageSize
54		rows, err := s.pool.Query(ctx,
55			`SELECT id, order_id, sender_id, body, attachment_path, attachment_size, attachment_mime, created_at
56			 FROM messages WHERE order_id = $1
57			 ORDER BY created_at ASC LIMIT $2 OFFSET $3`, orderID, pageSize, offset)
