15	type OrderService struct {
16		orderStore       *store.OrderStore
17		collectibleStore *store.CollectibleStore
18		notifService     *NotificationService
19		analyticsStore   *store.AnalyticsStore
20	}
21	
22	func NewOrderService(os *store.OrderStore, cs *store.CollectibleStore, ns *NotificationService, as *store.AnalyticsStore) *OrderService {
23		return &OrderService{orderStore: os, collectibleStore: cs, notifService: ns, analyticsStore: as}
24	}
25	
26	func (s *OrderService) Create(ctx context.Context, req dto.CreateOrderRequest, buyerID uuid.UUID, idempotencyKey string) (*model.Order, error) {
27		existing, err := s.orderStore.GetByIdempotencyKey(ctx, buyerID, idempotencyKey)
28		if err != nil {
29			s.emitEvent(ctx, &buyerID, "checkout_failed", &req.CollectibleID)
30			return nil, fmt.Errorf("check idempotency: %w", err)
31		}
32		if existing != nil {
33			return existing, nil
34		}
35	
36		collectible, err := s.collectibleStore.GetByID(ctx, req.CollectibleID)
37		if err != nil {
38			return nil, fmt.Errorf("get collectible: %w", err)
39		}
40		if collectible == nil {
41			s.emitEvent(ctx, &buyerID, "checkout_failed", &req.CollectibleID)
42			return nil, dto.ErrNotFound
43		}
44		if collectible.Status != "published" {
45			s.emitEvent(ctx, &buyerID, "checkout_failed", &req.CollectibleID)
46			return nil, dto.ErrNotFound
47		}
48		if collectible.SellerID == buyerID {
49			s.emitEvent(ctx, &buyerID, "checkout_failed", &req.CollectibleID)
50			return nil, fmt.Errorf("%w: cannot buy your own collectible", dto.ErrValidation)
51		}
52	
53		tx, err := s.orderStore.BeginTx(ctx)
54		if err != nil {
55			s.emitEvent(ctx, &buyerID, "checkout_failed", &req.CollectibleID)
56			return nil, fmt.Errorf("begin tx: %w", err)
57		}
58		defer tx.Rollback(ctx)
59	
60		if err := s.orderStore.AcquireAdvisoryLock(ctx, tx, req.CollectibleID); err != nil {
61			s.emitEvent(ctx, &buyerID, "checkout_failed", &req.CollectibleID)
62			return nil, fmt.Errorf("acquire lock: %w", err)
63		}
64	
65		hasActive, err := s.orderStore.HasActiveOrder(ctx, tx, req.CollectibleID)
66		if err != nil {
67			s.emitEvent(ctx, &buyerID, "checkout_failed", &req.CollectibleID)
68			return nil, fmt.Errorf("check active orders: %w", err)
69		}
70		if hasActive {
71			s.emitEvent(ctx, &buyerID, "checkout_failed", &req.CollectibleID)
72			return nil, dto.ErrOversold
73		}
74	
75		order := &model.Order{
76			IdempotencyKey:     idempotencyKey,
77			BuyerID:            buyerID,
78			CollectibleID:      req.CollectibleID,
79			SellerID:           collectible.SellerID,
80			Status:             model.OrderStatusPending,
81			PriceSnapshotCents: collectible.PriceCents,
82		}
83	
84		if err := s.orderStore.CreateInTx(ctx, tx, order); err != nil {
85			s.emitEvent(ctx, &buyerID, "checkout_failed", &req.CollectibleID)
86			return nil, fmt.Errorf("create order: %w", err)
87		}
88	
89		transition := &model.OrderStateTransition{
90			OrderID:    order.ID,
91			FromStatus: "",
92			ToStatus:   model.OrderStatusPending,
93			ActorID:    buyerID,
94			Reason:     "order created",
95		}
96		if err := s.orderStore.RecordTransitionInTx(ctx, tx, transition); err != nil {
97			s.emitEvent(ctx, &buyerID, "checkout_failed", &req.CollectibleID)
98			return nil, fmt.Errorf("record transition: %w", err)
99		}
100	
101		if err := tx.Commit(ctx); err != nil {
102			s.emitEvent(ctx, &buyerID, "checkout_failed", &req.CollectibleID)
103			return nil, fmt.Errorf("commit: %w", err)
104		}
105	
106		// Emit analytics event
107		s.emitEvent(ctx, &buyerID, "order_created", &req.CollectibleID)
108	
109		return order, nil
110	}
111	
112	// GetByID with object-level authorization: only buyer or seller of the order can view it.
113	func (s *OrderService) GetByID(ctx context.Context, id uuid.UUID, actorID uuid.UUID) (*model.Order, error) {
114		order, err := s.orderStore.GetByID(ctx, id)
115		if err != nil {
116			return nil, err
117		}
118		if order == nil {
119			return nil, dto.ErrNotFound
120		}
121		if order.BuyerID != actorID && order.SellerID != actorID {
122			return nil, dto.ErrForbidden
123		}
124		return order, nil
125	}
126	
127	// TransitionStatus with object-level authorization.
128	// Confirm/Process/Complete: only the seller of THIS order.
129	// Cancel: only the buyer or seller of THIS order.
130	func (s *OrderService) TransitionStatus(ctx context.Context, orderID uuid.UUID, targetStatus model.OrderStatus, actorID uuid.UUID, reason string) (*model.Order, error) {
131		order, err := s.orderStore.GetByID(ctx, orderID)
132		if err != nil {
133			return nil, err
134		}
135		if order == nil {
136			return nil, dto.ErrNotFound
137		}
138	
139		// Object-level authorization
140		switch targetStatus {
141		case model.OrderStatusConfirmed, model.OrderStatusProcessing, model.OrderStatusCompleted:
142			if order.SellerID != actorID {
143				return nil, fmt.Errorf("%w: only the seller of this order can perform this action", dto.ErrForbidden)
144			}
145		case model.OrderStatusCancelled:
146			if order.BuyerID != actorID && order.SellerID != actorID {
147				return nil, fmt.Errorf("%w: only the buyer or seller of this order can cancel it", dto.ErrForbidden)
148			}
149		}
150	
151		if !order.Status.CanTransitionTo(targetStatus) {
152			s.emitEvent(ctx, &actorID, "checkout_failed", &order.CollectibleID)
153			return nil, fmt.Errorf("%w: cannot transition from %s to %s", dto.ErrInvalidTransition, order.Status, targetStatus)
154		}
155	
156		if targetStatus == model.OrderStatusCancelled {
157			if err := s.orderStore.Cancel(ctx, orderID, reason, actorID); err != nil {
158				s.emitEvent(ctx, &actorID, "checkout_failed", &order.CollectibleID)
159				return nil, fmt.Errorf("cancel order: %w", err)
160			}
161			s.emitEvent(ctx, &actorID, "order_cancelled", &order.CollectibleID)
162		} else {
163			if err := s.orderStore.UpdateStatus(ctx, orderID, targetStatus); err != nil {
164				s.emitEvent(ctx, &actorID, "checkout_failed", &order.CollectibleID)
165				return nil, fmt.Errorf("update status: %w", err)
166			}
167			// Emit transition events so AB tests and funnels track the full order lifecycle.
168			// Attribution: use the BUYER's identity for variant tagging so that
169			// conversion metrics reflect the user who made the purchase decision,
170			// not the seller who fulfilled it.
171			statusEventMap := map[model.OrderStatus]string{
172				model.OrderStatusConfirmed: "order_confirmed",
173				model.OrderStatusCompleted: "order_completed",
174			}
175			if eventType, ok := statusEventMap[targetStatus]; ok {
176				s.emitEvent(ctx, &order.BuyerID, eventType, &order.CollectibleID)
177			}
178		}
179	
180		transition := &model.OrderStateTransition{
181			OrderID:    orderID,
182			FromStatus: order.Status,
183			ToStatus:   targetStatus,
184			ActorID:    actorID,
185			Reason:     reason,
186		}
187		if err := s.orderStore.RecordTransition(ctx, transition); err != nil {
188			return nil, fmt.Errorf("record transition: %w", err)
189		}
190	
191		// On completion, record an immutable transaction history entry for the
192		// collectible, representing the ownership transfer from seller to buyer.
193		if targetStatus == model.OrderStatusCompleted {
194			s.recordOwnershipTransfer(ctx, order)
195		}
196	
197		s.sendOrderNotification(ctx, order, targetStatus, reason)
198	
199		order.Status = targetStatus
200		return order, nil
201	}
202	
203	// ApproveRefund marks a refund as approved for the given order and emits
204	// the refund_approved notification to the buyer.
205	func (s *OrderService) ApproveRefund(ctx context.Context, orderID uuid.UUID, actorID uuid.UUID, reason string) (*model.Order, error) {
206		order, err := s.orderStore.GetByID(ctx, orderID)
207		if err != nil {
208			return nil, err
209		}
210		if order == nil {
211			return nil, dto.ErrNotFound
212		}
213	
214		// Only the seller or an admin can approve a refund
215		if order.SellerID != actorID {
216			return nil, fmt.Errorf("%w: only the seller of this order can approve a refund", dto.ErrForbidden)
217		}
218	
219		// Refunds can only be approved on completed or cancelled orders
220		if order.Status != model.OrderStatusCompleted && order.Status != model.OrderStatusCancelled {
221			return nil, fmt.Errorf("%w: refunds can only be approved on completed or cancelled orders", dto.ErrValidation)
222		}
223	
224		// Emit analytics event after successful refund approval
225		s.emitEvent(ctx, &actorID, "refund_approved", &order.CollectibleID)
226	
227		// Send notification to the buyer
228		s.sendRefundNotification(ctx, order, reason)
229	
230		return order, nil
231	}
