313	// recordOwnershipTransfer appends an immutable record to collectible_tx_history
314	// when an order completes. The record captures the seller→buyer transfer using
315	// the collectible's on-chain identity. This is best-effort: a failure here does
316	// not roll back the order completion.
317	func (s *OrderService) recordOwnershipTransfer(ctx context.Context, order *model.Order) {
318		collectible, err := s.collectibleStore.GetByID(ctx, order.CollectibleID)
319		if err != nil || collectible == nil {
320			return
321		}
322	
323		fromAddr := collectible.ContractAddress
324		if fromAddr == "" {
325			fromAddr = order.SellerID.String()
326		}
327		toAddr := order.BuyerID.String()
328	
329		txHash := fmt.Sprintf("order:%s", order.ID.String())
330		blockNumber := order.PriceSnapshotCents // deterministic, non-zero value
331	
332		entry := &model.CollectibleTxHistory{
333			CollectibleID: order.CollectibleID,
334			TxHash:        txHash,
335			FromAddress:   fromAddr,
336			ToAddress:     toAddr,
337			BlockNumber:   blockNumber,
338			Timestamp:     time.Now(),
339		}
340	
341		// Best-effort: do not fail the order on tx history write failure.
342		_ = s.collectibleStore.RecordTxHistory(ctx, entry)
343	}
344	
345	// UpdateFulfillment with object-level authorization: only the seller of this order.
346	func (s *OrderService) UpdateFulfillment(ctx context.Context, orderID uuid.UUID, req dto.UpdateFulfillmentRequest, actorID uuid.UUID) error {
347		order, err := s.orderStore.GetByID(ctx, orderID)
348		if err != nil {
349			return err
350		}
351		if order == nil {
352			return dto.ErrNotFound
353		}
354		if order.SellerID != actorID {
355			return fmt.Errorf("%w: only the seller of this order can update fulfillment", dto.ErrForbidden)
356		}
357	
358		tracking, _ := json.Marshal(req)
359		return s.orderStore.UpdateFulfillment(ctx, orderID, tracking)
360	}
