	"github.com/google/uuid"
	"github.com/jackc/pgx/v5"
	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/ledgermint/platform/internal/model"
)

type MessageStore struct {
	pool *pgxpool.Pool
}

func NewMessageStore(pool *pgxpool.Pool) *MessageStore {
	return &MessageStore{pool: pool}
}

func (s *MessageStore) GetByID(ctx context.Context, id uuid.UUID) (*model.Message, error) {
	var m model.Message
	err := s.pool.QueryRow(ctx,
		`SELECT id, order_id, sender_id, body, attachment_data, attachment_size, attachment_mime, created_at
		 FROM messages WHERE id = $1`, id).Scan(
		&m.ID, &m.OrderID, &m.SenderID, &m.Body, &m.AttachmentData,
		&m.AttachmentSize, &m.AttachmentMime, &m.CreatedAt)
	if err == pgx.ErrNoRows {
		return nil, nil
	}
	if len(m.AttachmentData) > 0 {
		m.AttachmentID = m.ID.String()
	}
	return &m, err
}

func (s *MessageStore) Create(ctx context.Context, m *model.Message) error {
	return s.pool.QueryRow(ctx,
		`INSERT INTO messages (order_id, sender_id, body, attachment_data, attachment_size, attachment_mime)
		 VALUES ($1, $2, $3, $4, $5, $6)
		 RETURNING id, created_at`,
		m.OrderID, m.SenderID, m.Body, m.AttachmentData, m.AttachmentSize, m.AttachmentMime,
	).Scan(&m.ID, &m.CreatedAt)
}

func (s *MessageStore) ListByOrder(ctx context.Context, orderID uuid.UUID, page, pageSize int) ([]model.Message, int, error) {
	var total int
	err := s.pool.QueryRow(ctx,
		`SELECT COUNT(*) FROM messages WHERE order_id = $1`, orderID).Scan(&total)
	if err != nil {
		return nil, 0, err
	}

	offset := (page - 1) * pageSize
	rows, err := s.pool.Query(ctx,
		`SELECT id, order_id, sender_id, body, attachment_size, attachment_mime, created_at
		 FROM messages WHERE order_id = $1
		 ORDER BY created_at ASC LIMIT $2 OFFSET $3`, orderID, pageSize, offset)
	if err != nil {
		return nil, 0, err
	}
	defer rows.Close()

	var messages []model.Message
	for rows.Next() {
		var m model.Message
		if err := rows.Scan(&m.ID, &m.OrderID, &m.SenderID, &m.Body,
			&m.AttachmentSize, &m.AttachmentMime, &m.CreatedAt); err != nil {
			return nil, 0, err
		}
		if m.AttachmentSize > 0 {
			m.AttachmentID = m.ID.String()
		}
		messages = append(messages, m)
	}
	return messages, total, nil
}
"}

