4		"testing"
5	
6		"github.com/ledgermint/platform/internal/service"
7	)
8	
9	func TestIsTextAttachment(t *testing.T) {
10		tests := []struct {
11			mime, ext string
12			want      bool
13		}{
14			{"text/plain", ".txt", true},
15			{"text/csv", ".csv", true},
16			{"text/html", ".html", true},
17			{"application/octet-stream", ".csv", true},
18			{"application/octet-stream", ".txt", true},
19			{"image/png", ".png", false},
20			{"application/pdf", ".pdf", false},
21		}
