{"file_path": "/Users/macbookpro/Projects/eaglepoint/w1t21/repo/backend/internal/handler/message_body_validation_test.go", "content": "package handler

import (
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"

	"github.com/labstack/echo/v4"
	"github.com/ledgermint/platform/internal/dto"
)

// TestSendMessage_BodyTooLong verifies that the handler rejects message bodies
// exceeding the 5000 character limit with a 422 status and ERR_VALIDATION code.
func TestSendMessage_BodyTooLong(t *testing.T) {
	e := echo.New()

	// 5001 characters — just over the limit
	longBody := strings.Repeat("a", 5001)
	formBody := "body=" + longBody

	req := httptest.NewRequest(http.MethodPost, "/api/orders/00000000-0000-0000-0000-000000000001/messages", strings.NewReader(formBody))
	req.Header.Set(echo.HeaderContentType, "application/x-www-form-urlencoded")
	rec := httptest.NewRecorder()
	c := e.NewContext(req, rec)
	c.SetParamNames("orderId")
	c.SetParamValues("00000000-0000-0000-0000-000000000001")
	c.Set("user_id", "00000000-0000-0000-0000-000000000002")

	h := &MessageHandler{}
	_ = h.Send(c)

	if rec.Code != http.StatusUnprocessableEntity {
		t.Fatalf("expected 422, got %d", rec.Code)
	}

	var body dto.ErrorResponse
	if err := json.Unmarshal(rec.Body.Bytes(), &body); err != nil {
		t.Fatalf("failed to decode response: %v", err)
	}
	if body.Error.Code != dto.CodeValidation {
		t.Errorf("expected code %q, got %q", dto.CodeValidation, body.Error.Code)
	}
	if !strings.Contains(body.Error.Message, "5000") {
		t.Errorf("expected message to mention limit, got: %q", body.Error.Message)
	}
}

// TestSendMessage_BodyExactlyAtLimit verifies 5000 chars is accepted (not
// rejected at the body-length gate). The handler will still fail downstream
