1	package middleware
2	
3	import (
4		"github.com/google/uuid"
5		"github.com/labstack/echo/v4"
6		"go.uber.org/zap"
7	)
8	
9	const (
10		RequestIDKey = "request_id"
11		loggerKey    = "ctx_logger"
12	)
13	
14	// RequestID generates or propagates a request ID and, when a base logger is
15	// provided, stores a child logger enriched with that ID in the context.
16	func RequestID(baseLogger ...*zap.Logger) echo.MiddlewareFunc {
17		return func(next echo.HandlerFunc) echo.HandlerFunc {
18			return func(c echo.Context) error {
19				id := c.Request().Header.Get("X-Request-ID")
20				if id == "" {
21					id = uuid.New().String()
22				}
23				c.Set(RequestIDKey, id)
24				c.Response().Header().Set("X-Request-ID", id)
25	
26				if len(baseLogger) > 0 && baseLogger[0] != nil {
27					c.Set(loggerKey, baseLogger[0].With(zap.String("request_id", id)))
28				}
29				return next(c)
30			}
31		}
32	}
33	
34	func GetRequestID(c echo.Context) string {
35		if id, ok := c.Get(RequestIDKey).(string); ok {
36			return id
37		}
38		return ""
39	}
40	
41	// Logger returns the request-scoped logger (with request_id) stored in the
42	// context, or a no-op production logger if none was set.
43	func Logger(c echo.Context) *zap.Logger {
44		if l, ok := c.Get(loggerKey).(*zap.Logger); ok {
45			return l
46		}
47		l, _ := zap.NewProduction()
48		return l
49	}
