1	package handler
2	
3	import (
4		"bytes"
5		"io"
6		"net/http"
7		"path/filepath"
8		"strings"
9	
10		"github.com/google/uuid"
11		"github.com/labstack/echo/v4"
12		"github.com/ledgermint/platform/internal/dto"
13		"github.com/ledgermint/platform/internal/middleware"
14		"github.com/ledgermint/platform/internal/service"
15	)
16	
17	type MessageHandler struct {
18		messageService *service.MessageService
19	}
20	
21	func NewMessageHandler(ms *service.MessageService) *MessageHandler {
22		return &MessageHandler{messageService: ms}
23	}
24	
25	func (h *MessageHandler) List(c echo.Context) error {
26		orderID, err := uuid.Parse(c.Param("orderId"))
27		if err != nil {
28			return errorResponse(c, http.StatusBadRequest, dto.CodeValidation, "invalid order ID")
29		}
30	
31		userID, err := uuid.Parse(middleware.GetUserID(c))
32		if err != nil {
33			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "invalid user")
34		}
35	
36		page, pageSize := pagination(c)
37		messages, total, err := h.messageService.ListByOrder(c.Request().Context(), orderID, userID, page, pageSize)
38		if err != nil {
39			return mapError(c, err)
40		}
41		return paginatedResponse(c, messages, page, pageSize, total)
42	}
43	
44	func (h *MessageHandler) Send(c echo.Context) error {
45		orderID, err := uuid.Parse(c.Param("orderId"))
46		if err != nil {
47			return errorResponse(c, http.StatusBadRequest, dto.CodeValidation, "invalid order ID")
48		}
49	
50		userID, err := uuid.Parse(middleware.GetUserID(c))
51		if err != nil {
52			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "invalid user")
53		}
54	
55		body := c.FormValue("body")
56		if body == "" {
57			return errorResponse(c, http.StatusUnprocessableEntity, dto.CodeValidation, "message body is required")
58		}
59		if len(body) > 5000 {
60			return errorResponse(c, http.StatusUnprocessableEntity, dto.CodeValidation, "message body exceeds 5000 character limit")
61		}
62	
63		// Server-side PII detection
64		if detected, piiTypes := service.DetectPII(body); detected {
65			return errorResponse(c, http.StatusUnprocessableEntity, dto.CodeValidation, service.PIIErrorMessage(piiTypes))
66		}
67	
68		var attachmentData []byte
69		var attachmentMime string
70		var attachmentSize int
71	
72		file, err := c.FormFile("attachment")
73		if err == nil {
74			// Server-side 10MB enforcement
75			if file.Size > service.MaxAttachmentSize {
76				return errorResponse(c, http.StatusRequestEntityTooLarge, dto.CodeAttachmentTooLarge, "attachment exceeds 10MB limit")
77			}
78	
79			src, err := file.Open()
80			if err != nil {
81				return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "failed to read attachment")
82			}
83			defer src.Close()
84	
85			mime := file.Header.Get("Content-Type")
86			ext := filepath.Ext(file.Filename)
87	
88			// Read the full attachment into memory before persisting so we can
89			// inspect it for PII regardless of format.
90			buf := &bytes.Buffer{}
91			if _, err := io.Copy(buf, src); err != nil {
92				return errorResponse(c, http.StatusInternalServerError, dto.CodeInternal, "failed to read attachment")
93			}
94	
95			// Reject file types that are neither scannable text nor an
96			// approved binary type (images, PDF, SVG).
97			if !isTextAttachment(mime, ext) && !isSafeBinaryAttachment(mime, ext) {
98				return errorResponse(c, http.StatusUnprocessableEntity, dto.CodeValidation,
99					"attachment type not allowed: "+mime+" ("+ext+"); supported types: images, PDF, plain text, CSV")
100			}
101	
102			// PII scan — applied to ALL attachments regardless of format.
103			scannableText := service.ExtractScannableText(buf.Bytes(), mime, ext)
104			if detected, piiTypes := service.DetectPII(scannableText); detected {
105				c.Logger().Warn("attachment PII blocked for order ", orderID.String())
106				return errorResponse(c, http.StatusUnprocessableEntity, dto.CodeValidation,
107					"attachment blocked: contains sensitive personal information ("+strings.Join(piiTypes, ", ")+")")
108			}
109	
110			attachmentData = buf.Bytes()
111			attachmentSize = int(file.Size)
112			attachmentMime = mime
113		}
114	
115		msg, err := h.messageService.Send(c.Request().Context(), orderID, userID, body,
116			attachmentData, attachmentSize, attachmentMime)
117		if err != nil {
118			return mapError(c, err)
119		}
120		return c.JSON(http.StatusCreated, msg)
121	}
122	
123	// DownloadAttachment serves an attachment by message ID directly from PostgreSQL.
124	// The binary data is stored in the database — no filesystem paths are involved.
125	func (h *MessageHandler) DownloadAttachment(c echo.Context) error {
126		msgID, err := uuid.Parse(c.Param("messageId"))
127		if err != nil {
128			return errorResponse(c, http.StatusBadRequest, dto.CodeValidation, "invalid message ID")
129		}
130	
131		userID, err := uuid.Parse(middleware.GetUserID(c))
132		if err != nil {
133			return errorResponse(c, http.StatusUnauthorized, dto.CodeUnauthorized, "invalid user")
134		}
135	
136		msg, err := h.messageService.GetByID(c.Request().Context(), msgID, userID)
137		if err != nil {
138			return mapError(c, err)
139		}
140	
141		if len(msg.AttachmentData) == 0 {
142			return errorResponse(c, http.StatusNotFound, dto.CodeNotFound, "no attachment on this message")
143		}
144	
145		c.Response().Header().Set("Content-Type", msg.AttachmentMime)
146		return c.Blob(http.StatusOK, msg.AttachmentMime, msg.AttachmentData)
147	}
148	
149	// isTextAttachment returns true for file types whose content should be scanned as text.
150	func isTextAttachment(mime string, ext string) bool {
151		if strings.HasPrefix(mime, "text/") {
152			return true
153		}
154		ext = strings.ToLower(ext)
155		return ext == ".csv" || ext == ".txt"
156	}
157	
158	// safeBinaryMIMEs lists binary MIME types that are allowed as attachments.
159	var safeBinaryMIMEs = map[string]bool{
160		"image/jpeg":      true,
161		"image/png":       true,
162		"image/gif":       true,
163		"image/webp":      true,
164		"image/svg+xml":   true,
165		"application/pdf": true,
166	}
167	
168	// safeBinaryExts provides a fallback when the MIME type from the client
169	// is generic (e.g. application/octet-stream).
170	var safeBinaryExts = map[string]bool{
171		".jpg": true, ".jpeg": true, ".png": true, ".gif": true,
172		".webp": true, ".svg": true, ".pdf": true,
173	}
174	
175	// isSafeBinaryAttachment returns true for binary file types that are
176	// explicitly allowed.
177	func isSafeBinaryAttachment(mime string, ext string) bool {
178		if safeBinaryMIMEs[mime] {
179			return true
180		}
181		return safeBinaryExts[strings.ToLower(ext)]
182	}
183	
