39			 VALUES ($1, $2, $3, $4, $5, $6)
40			 RETURNING id, created_at`,
41			m.OrderID, m.SenderID, m.Body, m.AttachmentData, m.AttachmentSize, m.AttachmentMime,
42		).Scan(&m.ID, &m.CreatedAt)
43	}
44	
45	func (s *MessageStore) ListByOrder(ctx context.Context, orderID uuid.UUID, page, pageSize int) ([]model.Message, int, error) {
46		var total int
47		err := s.pool.QueryRow(ctx,
48			`SELECT COUNT(*) FROM messages WHERE order_id = $1`, orderID).Scan(&total)
49		if err != nil {
50			return nil, 0, err
51		}
52	
53		offset := (page - 1) * pageSize
54		rows, err := s.pool.Query(ctx,
55			`SELECT id, order_id, sender_id, body, attachment_size, attachment_mime, created_at
56			 FROM messages WHERE order_id = $1
57			 ORDER BY created_at ASC LIMIT $2 OFFSET $3`, orderID, pageSize, offset)
58		if err != nil {
59			return nil, 0, err
60		}
61		defer rows.Close()
62	
63		var messages []model.Message
64		for rows.Next() {
65			var m model.Message
66			if err := rows.Scan(&m.ID, &m.OrderID, &m.SenderID, &m.Body,
67				&m.AttachmentSize, &m.AttachmentMime, &m.CreatedAt); err != nil {
68				return nil, 0, err
69			}
70			if m.AttachmentSize > 0 {
71				m.AttachmentID = m.ID.String()
72			}
73			messages = append(messages, m)
74		}
75		return messages, total, nil
76	}
